"""Async Connect JSON transport, mirroring `_connect.ConnectTransport`.

The async transport reuses the same `_ConnectStreamParser`, error parsing,
and envelope-encoding helpers as the sync transport so framing stays
byte-for-byte identical between the two paths.
"""

from __future__ import annotations

import json
import asyncio
from collections.abc import AsyncIterator
from typing import Any, Mapping
from urllib.parse import urljoin

import httpx

from ._connect import (
    DEFAULT_UNARY_TIMEOUT_SECONDS,
    _ConnectStreamParser,
    _TransportBase,
    _bridge_shutdown_request,
    _http_error,
    _is_retry_safe_method,
    _is_retryable_status,
    _json_loads,
    _LOG,
    _network_error,
    encode_stream_envelope,
)
from .types import JsonObject


class DefaultAsyncHttpxClient(httpx.AsyncClient):
    """`httpx.AsyncClient` subclass with the Cursor SDK's defaults.

    Mirrors `openai.DefaultAsyncHttpxClient`: callers who want to customize
    the async HTTP client can subclass or instantiate this directly and keep
    the SDK's defaults for `timeout` and `follow_redirects`.
    """

    def __init__(self, **kwargs: Any) -> None:
        kwargs.setdefault("timeout", DEFAULT_UNARY_TIMEOUT_SECONDS)
        kwargs.setdefault("follow_redirects", True)
        super().__init__(**kwargs)


class AsyncConnectTransport(_TransportBase):
    """Async Connect JSON transport for unary and server-streaming bridge RPCs.

    Wraps an `httpx.AsyncClient`. If `http_client` is supplied, the transport
    uses it as-is and does not close it; otherwise it owns the underlying
    client and `await aclose()` will dispose of it.

    Inherits timeout resolution, header building, and `with_options` from
    `_TransportBase`; only the I/O methods (sync vs async) are overridden.
    """

    _default_client_class = DefaultAsyncHttpxClient

    async def aclose(self) -> None:
        if self._owns_client:
            await self._client.aclose()

    async def __aenter__(self) -> "AsyncConnectTransport":
        return self

    async def __aexit__(self, *exc: Any) -> None:
        await self.aclose()

    async def unary(
        self, service: str, method: str, message: Mapping[str, Any]
    ) -> JsonObject:
        body = json.dumps(message).encode("utf-8")
        headers = self._headers(
            accept="application/json", content_type="application/json"
        )
        url = urljoin(self.base_url, f"{service}/{method}")
        response = await _apost_with_retries(
            self._client,
            url,
            body,
            headers,
            self._httpx_timeout(self.unary_timeout),
            max_retries=self.max_retries,
            service=service,
            method=method,
        )
        body_bytes = response.content
        if not body_bytes:
            return {}
        return _json_loads(body_bytes)

    async def stream(
        self, service: str, method: str, message: Mapping[str, Any]
    ) -> AsyncIterator[JsonObject]:
        body = encode_stream_envelope(message)
        headers = self._headers(
            accept="application/connect+json",
            content_type="application/connect+json",
        )
        url = urljoin(self.base_url, f"{service}/{method}")
        return _aiter_stream(
            self._client,
            url,
            body,
            headers,
            self._httpx_timeout(self.stream_timeout),
        )


async def _apost_with_retries(
    client: httpx.AsyncClient,
    url: str,
    body: bytes,
    headers: Mapping[str, str],
    timeout: Any,
    *,
    max_retries: int,
    service: str,
    method: str,
) -> httpx.Response:
    # Mirror `_post_with_retries`: mutating / unknown RPCs are not retried
    # at the transport level, so a network blip cannot silently replay a
    # destructive operation regardless of the caller's `max_retries`.
    effective_max_retries = max_retries if _is_retry_safe_method(method) else 0
    for attempt in range(effective_max_retries + 1):
        try:
            _LOG.debug(
                "cursor sdk async unary %s/%s attempt=%s", service, method, attempt + 1
            )
            response = await client.post(
                url,
                content=body,
                headers=headers,
                timeout=timeout,
            )
        except httpx.RequestError as error:
            if attempt < effective_max_retries:
                await _async_sleep_before_retry(attempt)
                continue
            raise _network_error(error) from error
        if response.status_code < 400:
            return response
        if attempt < effective_max_retries and _is_retryable_status(
            response.status_code
        ):
            await _async_sleep_before_retry(attempt)
            continue
        raise _http_error(response.status_code, response.content, response.headers)
    raise RuntimeError("unreachable")


async def _async_sleep_before_retry(attempt: int) -> None:
    await asyncio.sleep(min(0.25 * (2**attempt), 2.0))


async def post_bridge_shutdown(
    base_url: str, auth_token: str, *, grace_seconds: int = 0
) -> None:
    """Async mirror of `_connect.post_bridge_shutdown`. Used by
    `AsyncBridge.aclose` to break the `_async_bridge -> _async_client`
    cycle.
    """
    url, body, headers = _bridge_shutdown_request(
        base_url, auth_token, grace_seconds=grace_seconds
    )
    try:
        async with DefaultAsyncHttpxClient(
            timeout=DEFAULT_UNARY_TIMEOUT_SECONDS
        ) as client:
            await client.post(url, content=body, headers=headers)
    except httpx.RequestError:
        pass


async def _aiter_stream(
    client: httpx.AsyncClient,
    url: str,
    body: bytes,
    headers: Mapping[str, str],
    timeout: Any,
) -> AsyncIterator[JsonObject]:
    try:
        async with client.stream(
            "POST",
            url,
            content=body,
            headers=headers,
            timeout=timeout,
        ) as response:
            if response.status_code >= 400:
                raise _http_error(
                    response.status_code,
                    await response.aread(),
                    response.headers,
                )
            parser = _ConnectStreamParser(status=response.status_code)
            async for chunk in response.aiter_raw():
                for envelope in parser.feed(chunk):
                    yield envelope
                if parser.ended:
                    return
            parser.assert_ended()
    except httpx.RequestError as error:
        raise _network_error(error) from error
